/**
 * @fileoverview DragDrop component — modular entry point.
 *
 * Orchestrates sub-modules:
 *   constants.js — CSS classes, ARIA attrs, default config
 *   helpers.js   — cross-container group registry
 *   view.js      — DOM setup / teardown + placeholder management
 *   events.js    — centralised event binding (AbortController cleanup)
 *
 * @module module/DragDrop
 */

import { default as razyui } from '../../index.js';

import { DEFAULTS, DATA_TRANSFER }                               from './constants.js';
import { registerGroup, unregisterGroup, getGroupPeers }         from './helpers.js';
import {
    createPlaceholder, sizeToElement, findInsertionPoint,
    removePlaceholder, markContainer, unmarkContainer, cleanupItems,
} from './view.js';
import { bindContainer, bindExternalZone, bindItem }             from './events.js';

const { isFn, isStr } = razyui;

/**
 * DragDrop — v2 modular rewrite (JIT-compatible)
 *
 * HTML5 Drag & Drop with sortable reordering, cross-container transfer,
 * drag handle support, visual placeholders, and rich callbacks.
 *
 * Usage:
 *   new DragDrop('#list', { items: '.card', sortable: true })
 *
 * Config:
 *   items        — selector for draggable children (default '.drag-item')
 *   handle       — selector within each item for the drag handle (optional)
 *   dropZone     — additional selector(s) for external drop targets
 *   group        — string group name for cross-container transfer
 *   sortable     — boolean — allow reordering within container (default true)
 *   placeholder  — boolean — show insertion placeholder (default true)
 *   axis         — 'x' | 'y' | null — constrain placeholder direction
 *   copy         — boolean — copy rather than move on cross-container drop
 *   dragClass    — CSS class added to dragging item (default 'is-dragging')
 *   overClass    — CSS class added to drop target on dragover (default 'is-dragover')
 *
 * Callbacks:
 *   onDragStart(item, e)                — fires when drag begins
 *   onDragEnd(item, e)                  — fires when drag ends (success or cancel)
 *   onDrop(item, target, index, e)      — fires on successful drop
 *   onReorder(item, fromIndex, toIndex) — fires after sortable reorder
 *   canDrop(item, target)               — return false to prevent drop
 *
 * getControl() API:
 *   .enable()    — re-enable dragging
 *   .disable()   — disable dragging
 *   .destroy()   — cleanup all listeners & DOM
 *   .refresh()   — re-scan items (after dynamic add/remove)
 */
const DragDrop = class {

    #container      = null;   // raw element
    #els            = null;   // Elements wrapper
    #config         = {};
    #disabled       = false;
    #destroyed      = false;
    #dragItem       = null;
    #placeholder    = null;
    #externalZones  = [];

    // AbortControllers for centralised cleanup
    #containerAC    = null;
    #zoneACs        = [];
    #itemACs        = new Map();

    constructor(selector, config = {}) {
        this.#els = razyui(selector);
        if (!this.#els.length) {
            console.warn('DragDrop: element not found \u2192', selector);
            return;
        }

        this.#container = this.#els[0];

        this.#config = { ...DEFAULTS, ...config };

        if (this.#config.group) registerGroup(this.#config.group, this);
        this.#init();
    }

    // ── Internal: find closest item from event ──
    #closestItem(target) {
        return target.closest(this.#config.items);
    }

    // ── Internal: get all current items ──
    #getItems() {
        return [...this.#container.querySelectorAll(this.#config.items)];
    }

    // ═══════════════════════════════════════
    //  Setup
    // ═══════════════════════════════════════

    #init() {
        const cfg       = this.#config;
        const container = this.#container;

        // Mark container
        markContainer(this.#els);

        // Bind draggable items
        this.#bindItems();

        // ── Container as drop zone ──
        this.#containerAC = bindContainer(container, {
            dragover: (e) => {
                if (this.#disabled || !this.#dragItem) return;
                e.preventDefault();
                e.dataTransfer.dropEffect = cfg.copy ? 'copy' : 'move';
                this.#els.addClass(cfg.overClass);

                if (cfg.sortable && cfg.placeholder) {
                    this.#positionPlaceholder(e);
                }
            },
            dragleave: (e) => {
                if (!container.contains(e.relatedTarget)) {
                    this.#els.removeClass(cfg.overClass);
                    this.#doRemovePlaceholder();
                }
            },
            drop: (e) => {
                e.preventDefault();
                this.#els.removeClass(cfg.overClass);
                this.#handleDrop(container, e);
            },
        });

        // ── External drop zones ──
        if (cfg.dropZone) {
            const zones = razyui(cfg.dropZone);
            zones.each((zone) => {
                this.#externalZones.push(zone);
                const $zone = razyui(zone);

                const zoneAC = bindExternalZone(zone, {
                    dragover: (ev) => {
                        if (this.#disabled || !this.#dragItem) return;
                        ev.preventDefault();
                        ev.dataTransfer.dropEffect = cfg.copy ? 'copy' : 'move';
                        $zone.addClass(cfg.overClass);
                    },
                    dragleave: (ev) => {
                        if (!zone.contains(ev.relatedTarget)) {
                            $zone.removeClass(cfg.overClass);
                        }
                    },
                    drop: (ev) => {
                        ev.preventDefault();
                        $zone.removeClass(cfg.overClass);
                        this.#handleDrop(zone, ev);
                    },
                });
                this.#zoneACs.push(zoneAC);
            });
        }
    }

    #bindItems() {
        const cfg = this.#config;
        const ctx = {
            dragStart:  (item, e) => this.#onDragStart(item, e),
            dragEnd:    (item, e) => this.#onDragEnd(item, e),
            touchStart: (item, e) => this.#touchStart(item, e),
            touchMove:  (item, e) => this.#touchMove(item, e),
            touchEnd:   (item, e) => this.#touchEnd(item, e),
        };

        this.#getItems().forEach(item => {
            if (item._ddBound) return;
            item._ddBound = true;
            const ac = bindItem(item, ctx, cfg);
            this.#itemACs.set(item, ac);
        });
    }

    // ═══════════════════════════════════════
    //  Drag handlers
    // ═══════════════════════════════════════

    #onDragStart(item, e) {
        if (this.#disabled) { e.preventDefault(); return; }

        const cfg = this.#config;
        this.#dragItem = cfg.copy ? item.cloneNode(true) : item;
        razyui(item).addClass(cfg.dragClass);

        e.dataTransfer.effectAllowed = cfg.copy ? 'copy' : 'move';
        e.dataTransfer.setData(DATA_TRANSFER.TYPE, DATA_TRANSFER.VALUE);

        if (cfg.placeholder) {
            this.#placeholder = createPlaceholder();
            sizeToElement(this.#placeholder, item);
        }

        if (isFn(cfg.onDragStart)) cfg.onDragStart(item, e);

        // Notify group peers
        if (cfg.group) {
            getGroupPeers(cfg.group, this).forEach(peer => {
                peer._acceptForeignDrag(this.#dragItem, this);
            });
        }
    }

    #onDragEnd(item, e) {
        const cfg = this.#config;
        const $item = razyui(item);
        $item.removeClass(cfg.dragClass);
        if (cfg.handle) $item.removeAttr('draggable');

        this.#doRemovePlaceholder();
        this.#els.removeClass(cfg.overClass);
        this.#externalZones.forEach(z => razyui(z).removeClass(cfg.overClass));

        if (isFn(cfg.onDragEnd)) cfg.onDragEnd(item, e);
        this.#dragItem = null;

        // Notify group peers to stop accepting
        if (cfg.group) {
            getGroupPeers(cfg.group, this).forEach(peer => {
                peer._clearForeignDrag();
            });
        }
    }

    // ═══════════════════════════════════════
    //  Placeholder positioning
    // ═══════════════════════════════════════

    #positionPlaceholder(e) {
        if (!this.#placeholder) return;
        const items     = this.#getItems().filter(i => i !== this.#dragItem && i !== this.#placeholder);
        const container = this.#container;
        const before    = findInsertionPoint(items, this.#config.axis, e.clientX, e.clientY);

        if (before) {
            container.insertBefore(this.#placeholder, before);
        } else {
            this.#els.append(this.#placeholder);
        }
    }

    #doRemovePlaceholder() {
        removePlaceholder(this.#placeholder);
    }

    // ═══════════════════════════════════════
    //  Touch support
    // ═══════════════════════════════════════

    #touchStart(item, e) {
        if (this.#disabled) return;
        const cfg = this.#config;
        this.#dragItem = cfg.copy ? item.cloneNode(true) : item;
        razyui(item).addClass(cfg.dragClass);

        if (cfg.placeholder) {
            this.#placeholder = createPlaceholder();
            sizeToElement(this.#placeholder, item);
            this.#container.insertBefore(this.#placeholder, item);
        }

        if (isFn(cfg.onDragStart)) cfg.onDragStart(item, e);

        if (cfg.group) {
            getGroupPeers(cfg.group, this).forEach(peer => {
                peer._acceptForeignDrag(this.#dragItem, this);
            });
        }
    }

    #touchMove(item, e) {
        if (!this.#dragItem) return;
        e.preventDefault();

        const cfg   = this.#config;
        const touch = e.touches[0];
        const el    = document.elementFromPoint(touch.clientX, touch.clientY);

        // Find which container we're over
        let targetContainer = this.#container;
        if (this.#externalZones.length) {
            for (const zone of this.#externalZones) {
                if (zone.contains(el)) {
                    targetContainer = zone;
                    break;
                }
            }
        }

        if (cfg.sortable && this.#placeholder) {
            const items  = this.#getItems().filter(i => i !== this.#dragItem && i !== this.#placeholder);
            const before = findInsertionPoint(items, cfg.axis, touch.clientX, touch.clientY);

            if (before) {
                targetContainer.insertBefore(this.#placeholder, before);
            } else if (this.#placeholder.parentNode !== targetContainer) {
                razyui(targetContainer).append(this.#placeholder);
            }
        }

        razyui(targetContainer).addClass(cfg.overClass);
    }

    #touchEnd(item, e) {
        if (!this.#dragItem) return;

        razyui(item).removeClass(this.#config.dragClass);
        const cfg = this.#config;

        // Determine target container
        let targetContainer = this.#container;
        if (this.#externalZones.length && this.#placeholder) {
            for (const zone of this.#externalZones) {
                if (zone.contains(this.#placeholder)) {
                    targetContainer = zone;
                    break;
                }
            }
        }

        // canDrop guard
        if (isFn(cfg.canDrop) && cfg.canDrop(this.#dragItem, targetContainer) === false) {
            this.#doRemovePlaceholder();
            this.#els.removeClass(cfg.overClass);
            this.#externalZones.forEach(z => razyui(z).removeClass(cfg.overClass));
            this.#dragItem = null;
            return;
        }

        const isInternal = targetContainer === this.#container;

        if (isInternal && cfg.sortable) {
            const fromIndex = [...this.#container.children].indexOf(item);
            if (this.#placeholder && this.#placeholder.parentNode === this.#container) {
                this.#container.insertBefore(this.#dragItem, this.#placeholder);
            } else {
                this.#els.append(this.#dragItem);
            }
            const toIndex = [...this.#container.children].indexOf(this.#dragItem);
            if (isFn(cfg.onReorder)) cfg.onReorder(this.#dragItem, fromIndex, toIndex);
        } else {
            if (cfg.copy) {
                razyui(targetContainer).append(this.#dragItem.cloneNode(true));
            } else if (this.#placeholder && this.#placeholder.parentNode === targetContainer) {
                targetContainer.insertBefore(this.#dragItem, this.#placeholder);
            } else {
                razyui(targetContainer).append(this.#dragItem);
            }
        }

        this.#doRemovePlaceholder();
        this.#els.removeClass(cfg.overClass);
        this.#externalZones.forEach(z => razyui(z).removeClass(cfg.overClass));

        const dropIdx = [...targetContainer.children].indexOf(this.#dragItem);
        if (isFn(cfg.onDrop)) cfg.onDrop(this.#dragItem, targetContainer, dropIdx, e);

        if (isFn(cfg.onDragEnd)) cfg.onDragEnd(this.#dragItem, e);

        if (cfg.group) {
            getGroupPeers(cfg.group, this).forEach(peer => {
                peer._clearForeignDrag();
            });
        }

        this.#dragItem = null;
    }

    // ═══════════════════════════════════════
    //  Drop handler
    // ═══════════════════════════════════════

    #handleDrop(target, e) {
        const item = this.#dragItem;
        if (!item) return;

        const cfg = this.#config;

        // canDrop guard
        if (isFn(cfg.canDrop) && cfg.canDrop(item, target) === false) {
            this.#doRemovePlaceholder();
            return;
        }

        const isInternal = target === this.#container;

        if (isInternal && cfg.sortable) {
            const fromIndex = [...this.#container.children].indexOf(item);
            if (this.#placeholder && this.#placeholder.parentNode === this.#container) {
                this.#container.insertBefore(item, this.#placeholder);
            } else {
                this.#els.append(item);
            }
            const toIndex = [...this.#container.children].indexOf(item);
            if (isFn(cfg.onReorder)) cfg.onReorder(item, fromIndex, toIndex);
        } else {
            // External or cross-container drop
            if (cfg.copy) {
                razyui(target).append(item.cloneNode(true));
            } else if (this.#placeholder && this.#placeholder.parentNode === target) {
                target.insertBefore(item, this.#placeholder);
            } else {
                razyui(target).append(item);
            }
        }

        this.#doRemovePlaceholder();

        const dropIdx = [...target.children].indexOf(item);
        if (isFn(cfg.onDrop)) cfg.onDrop(item, target, dropIdx, e);
    }

    // ═══════════════════════════════════════
    //  Group cross-container support
    // ═══════════════════════════════════════

    _acceptForeignDrag(item, source) {
        this.#dragItem = item;
    }

    _clearForeignDrag() {
        this.#dragItem = null;
        this.#doRemovePlaceholder();
        this.#els.removeClass(this.#config.overClass);
    }

    // ═══════════════════════════════════════
    //  Public API
    // ═══════════════════════════════════════

    getControl() {
        const self = this;
        return {
            enable:  () => { self.#disabled = false; },
            disable: () => { self.#disabled = true; },
            refresh: () => self.#bindItems(),
            destroy: () => self.#destroy(),
            get element() { return self.#container; },
            get destroyed() { return self.#destroyed; },
        };
    }

    #destroy() {
        if (this.#destroyed) return;
        this.#destroyed = true;
        this.#disabled  = true;

        // Abort all event listeners
        this.#containerAC?.abort();
        this.#zoneACs.forEach(ac => ac.abort());
        this.#itemACs.forEach(ac => ac.abort());

        if (this.#config.group) unregisterGroup(this.#config.group, this);
        unmarkContainer(this.#els);
        cleanupItems(this.#getItems());
        this.#doRemovePlaceholder();
    }
};

export default DragDrop;
