/**
 * @fileoverview DragDrop constants — CSS classes, ARIA attributes, selectors, defaults.
 * @module module/DragDrop/constants
 */
import { defineParts } from '../shared/definePart.js';


/** CSS class names */
export const CLS = Object.freeze({
    CONTAINER:   'dd-container',
    PLACEHOLDER: 'dd-placeholder',
});

/** ARIA attribute names / values */
export const ARIA = Object.freeze({
    HIDDEN: 'aria-hidden',
});

/** DataTransfer constants */
export const DATA_TRANSFER = Object.freeze({
    TYPE:  'text/plain',
    VALUE: '',
});

/** Inline style constants */
export const STYLE = Object.freeze({
    CURSOR_GRAB:    'grab',
    TOUCH_NONE:     'none',
});

/** Default configuration values */
export const DEFAULTS = Object.freeze({
    items:       '.drag-item',
    handle:      null,
    dropZone:    null,
    group:       null,
    sortable:    true,
    placeholder: true,
    axis:        null,
    copy:        false,
    dragClass:   'is-dragging',
    overClass:   'is-dragover',
    onDragStart: null,
    onDragEnd:   null,
    onDrop:      null,
    onReorder:   null,
    canDrop:     null,
});

/** Semantic part names for pre-render styling overrides. */
export const PART = defineParts('DragDrop', {
    CONTAINER   : { class: 'dd-container', aliases: ['dd-container', 'container'] },
    PLACEHOLDER : { class: 'dd-placeholder', aliases: ['dd-placeholder', 'placeholder'] },
});

PART.CONTAINER.jit = 'relative [&_.is-dragging]:[opacity:var(--dd-drag-opacity)] [&_.is-dragging]:[cursor:grabbing_!important] [&_.is-dragover]:[outline:var(--dd-drop-outline-width)_solid_var(--rui-accent)] [&_.is-dragover]:[outline-offset:-2px] [&_.is-dragover]:bg-[var(--rui-accent-subtle)] [&_.drag-handle]:cursor-grab [&_.drag-handle]:active:[cursor:grabbing] [&_[draggable=true]]:cursor-grab [&_[draggable=true]:active]:cursor-grabbing';
PART.PLACEHOLDER.jit = '[border:var(--dd-placeholder-border-width)_dashed_var(--rui-accent)] rounded-[var(--dd-placeholder-radius)] bg-[var(--rui-accent-subtle)] [box-sizing:border-box] [transition:height_var(--rui-transition-normal)_var(--rui-transition-easing),width_var(--rui-transition-normal)_var(--rui-transition-easing)] pointer-events-none';