/**
 * @fileoverview DragDrop helpers — group registry for cross-container transfer.
 * @module module/DragDrop/helpers
 */

// ── Group registry (module-level singleton) ───────────
const groups = {};

/**
 * Register an instance under a named group.
 * @param {string} name  — group identifier
 * @param {object} instance — DragDrop instance
 */
export function registerGroup(name, instance) {
    if (!groups[name]) groups[name] = new Set();
    groups[name].add(instance);
}

/**
 * Unregister an instance from a named group.
 * @param {string} name
 * @param {object} instance
 */
export function unregisterGroup(name, instance) {
    if (groups[name]) {
        groups[name].delete(instance);
        if (!groups[name].size) delete groups[name];
    }
}

/**
 * Get all group peers excluding the given instance.
 * @param {string} name
 * @param {object} exclude — instance to omit
 * @returns {Array}
 */
export function getGroupPeers(name, exclude) {
    if (!groups[name]) return [];
    return [...groups[name]].filter(i => i !== exclude);
}
