/**
 * @fileoverview DragDrop events — centralised event binding via AbortController.
 * @module module/DragDrop/events
 */

import razyui from '../../index.js';
import { styleHandle, styleItem } from './view.js';

// ═══════════════════════════════════════
//  Container events
// ═══════════════════════════════════════

/**
 * Bind dragover / dragleave / drop on the main container.
 *
 * @param {HTMLElement} container
 * @param {object} handlers — { dragover, dragleave, drop }
 * @returns {AbortController}
 */
export function bindContainer(container, handlers) {
    const ac = new AbortController();
    const o  = { signal: ac.signal };

    const $container = razyui(container);

    $container.on('dragover',  handlers.dragover,  o);
    $container.on('dragleave', handlers.dragleave, o);
    $container.on('drop',      handlers.drop,      o);

    return ac;
}

// ═══════════════════════════════════════
//  External zone events
// ═══════════════════════════════════════

/**
 * Bind dragover / dragleave / drop on an external drop zone.
 *
 * @param {HTMLElement} zone
 * @param {object} handlers — { dragover, dragleave, drop }
 * @returns {AbortController}
 */
export function bindExternalZone(zone, handlers) {
    const ac = new AbortController();
    const o  = { signal: ac.signal };

    const $zone = razyui(zone);

    $zone.on('dragover',  handlers.dragover,  o);
    $zone.on('dragleave', handlers.dragleave, o);
    $zone.on('drop',      handlers.drop,      o);

    return ac;
}

// ═══════════════════════════════════════
//  Per-item events (drag + handle + touch)
// ═══════════════════════════════════════

/**
 * Bind all events on a single draggable item:
 *   - Handle pointer events (if configured)
 *   - dragstart / dragend
 *   - touchstart / touchmove / touchend
 *
 * @param {HTMLElement} item
 * @param {object} ctx — { dragStart(item,e), dragEnd(item,e),
 *                         touchStart(item,e), touchMove(item,e), touchEnd(item,e) }
 * @param {object} cfg — component config
 * @returns {AbortController}
 */
export function bindItem(item, ctx, cfg) {
    const ac = new AbortController();
    const o  = { signal: ac.signal };

    // ── Handle / draggable setup ──
    if (cfg.handle) {
        const handle = item.querySelector(cfg.handle);
        if (handle) {
            styleHandle(handle);
            const $handle = razyui(handle);
            const $item   = razyui(item);
            $handle.on('pointerdown', () => { $item.setAttr({ draggable: 'true' }); }, o);
            $handle.on('pointerup',   () => { $item.removeAttr('draggable'); }, o);

            // Touch on handle
            $handle.on('touchstart', e => ctx.touchStart(item, e), o);
            $handle.on('touchmove',  e => ctx.touchMove(item, e),  o);
            $handle.on('touchend',   e => ctx.touchEnd(item, e),   o);
        } else {
            const $item = razyui(item);
            $item.setAttr({ draggable: 'true' });

            // Touch on item (handle selector didn't match)
            $item.on('touchstart', e => ctx.touchStart(item, e), o);
            $item.on('touchmove',  e => ctx.touchMove(item, e),  o);
            $item.on('touchend',   e => ctx.touchEnd(item, e),   o);
        }
    } else {
        const $item = razyui(item);
        $item.setAttr({ draggable: 'true' });
        styleItem(item);

        // Touch on item
        $item.on('touchstart', e => ctx.touchStart(item, e), o);
        $item.on('touchmove',  e => ctx.touchMove(item, e),  o);
        $item.on('touchend',   e => ctx.touchEnd(item, e),   o);
    }

    // ── Drag events (always on item) ──
    const $dragItem = razyui(item);
    $dragItem.on('dragstart', e => ctx.dragStart(item, e), o);
    $dragItem.on('dragend',   e => ctx.dragEnd(item, e),   o);

    return ac;
}
